'use client'
import { createMachine, useMachine, useSignalEffect, useSignals } from '@cascivo/core'
import {
  cloneElement,
  useId,
  useRef,
  type CSSProperties,
  type FocusEvent,
  type HTMLAttributes,
  type MouseEvent,
  type ReactElement,
  type ReactNode,
} from 'react'
import styles from './tooltip.module.css'

const machine = createMachine({
  initial: 'hidden' as const,
  states: {
    hidden: { on: { SHOW: 'visible' } },
    visible: { on: { HIDE: 'hidden' } },
  },
})

export interface TooltipProps {
  content: ReactNode
  placement?: 'top' | 'right' | 'bottom' | 'left'
  children: ReactElement
  delay?: number
}

export function Tooltip({ content, placement = 'top', children, delay = 200 }: TooltipProps) {
  useSignals()
  const [state, send] = useMachine(machine)
  const tooltipId = useId()
  const anchorId = useRef(`t${Math.random().toString(36).slice(2)}`)
  const timer = useRef<ReturnType<typeof setTimeout> | undefined>(undefined)
  const floatingRef = useRef<HTMLSpanElement>(null)

  const isVisible = state.value === 'visible'

  const show = () => {
    clearTimeout(timer.current)
    timer.current = setTimeout(() => send('SHOW'), delay)
  }
  const hide = () => {
    clearTimeout(timer.current)
    send('HIDE')
  }

  useSignalEffect(() => () => clearTimeout(timer.current))

  useSignalEffect(() => {
    if (state.value === 'visible') {
      floatingRef.current?.showPopover()
    } else {
      floatingRef.current?.hidePopover()
    }
  })

  const trigger = children as ReactElement<HTMLAttributes<HTMLElement>>
  const triggerProps = trigger.props

  const merged: HTMLAttributes<HTMLElement> = {
    id: anchorId.current,
    style: { anchorName: `--tooltip-${anchorId.current}` } as CSSProperties,
    onMouseEnter: (event: MouseEvent<HTMLElement>) => {
      triggerProps.onMouseEnter?.(event)
      show()
    },
    onMouseLeave: (event: MouseEvent<HTMLElement>) => {
      triggerProps.onMouseLeave?.(event)
      hide()
    },
    onFocus: (event: FocusEvent<HTMLElement>) => {
      triggerProps.onFocus?.(event)
      show()
    },
    onBlur: (event: FocusEvent<HTMLElement>) => {
      triggerProps.onBlur?.(event)
      hide()
    },
    'aria-describedby': isVisible ? tooltipId : triggerProps['aria-describedby'],
  }

  return (
    <span className={styles['root']}>
      {cloneElement(trigger, merged)}
      <span
        ref={floatingRef}
        popover="manual"
        role="tooltip"
        id={tooltipId}
        data-placement={placement}
        data-state={isVisible ? 'visible' : 'hidden'}
        data-anchor={`--tooltip-${anchorId.current}`}
        className={styles['tooltip']}
      >
        {content}
      </span>
    </span>
  )
}

@layer cascivo.component {
  .root {
    position: relative;
    display: inline-flex;
  }

  .tooltip {
    position: absolute;
    z-index: var(--cascivo-z-tooltip);
    inline-size: max-content;
    max-inline-size: 16rem;
    padding-inline: var(--cascivo-space-3);
    padding-block: var(--cascivo-space-1);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-xs);
    line-height: var(--cascivo-leading-snug);
    color: var(--cascivo-color-text-on-accent);
    background-color: var(--cascivo-color-text);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-md);
    pointer-events: none;
    opacity: 0;
    visibility: hidden;
    transition:
      opacity var(--cascivo-motion-enter),
      visibility var(--cascivo-motion-enter);

    /* Reset default popover styles */
    &:popover-open {
      opacity: 1;
      visibility: visible;
    }

    &[data-state='visible'] {
      opacity: 1;
      visibility: visible;
    }

    @starting-style {
      &[data-state='visible'] {
        opacity: 0;
      }
    }

    &[data-placement='top'] {
      inset-block-end: calc(100% + var(--cascivo-space-2));
      inset-inline-start: 50%;
      translate: -50% 0;
    }
    &[data-placement='bottom'] {
      inset-block-start: calc(100% + var(--cascivo-space-2));
      inset-inline-start: 50%;
      translate: -50% 0;
    }
    &[data-placement='left'] {
      inset-inline-end: calc(100% + var(--cascivo-space-2));
      inset-block-start: 50%;
      translate: 0 -50%;
    }
    &[data-placement='right'] {
      inset-inline-start: calc(100% + var(--cascivo-space-2));
      inset-block-start: 50%;
      translate: 0 -50%;
    }
  }

  @supports (anchor-name: --a) and (position-anchor: --a) {
    .tooltip {
      position: fixed;
      inset: auto;
      position-anchor: var(--cascivo-tooltip-anchor, attr(data-anchor));
      margin: var(--cascivo-space-2);
    }

    .tooltip[data-placement='top'] {
      inset-area: block-start span-inline-start;
      translate: 0 0;
    }

    .tooltip[data-placement='bottom'] {
      inset-area: block-end span-inline-start;
      translate: 0 0;
    }

    .tooltip[data-placement='left'] {
      inset-area: inline-start span-block-start;
      translate: 0 0;
    }

    .tooltip[data-placement='right'] {
      inset-area: inline-end span-block-start;
      translate: 0 0;
    }

    @media (prefers-reduced-motion: no-preference) {
      .tooltip {
        transition:
          opacity var(--cascivo-motion-enter),
          visibility var(--cascivo-motion-enter),
          display var(--cascivo-motion-enter) allow-discrete,
          overlay var(--cascivo-motion-enter) allow-discrete;
      }

      @starting-style {
        .tooltip[data-state='visible'] {
          opacity: 0;
        }
      }
    }
  }
}

@media (forced-colors: active) {
  .tooltip {
    border: 1px solid CanvasText;
    background-color: Canvas;
    color: CanvasText;
  }
}
